import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, ChartsXAxis, ChartsYAxis, BarPlot, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface BudgetAllocation {
  department: string;
  budget: number;
}

interface FinanceData {
  budgetAllocation: BudgetAllocation[];
}

export default function Widget() {
  const financeData = response.data as FinanceData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E293B' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#94A3B8', mb: 0.5 }}>
              Budget Allocation
            </Typography>
          </Box>
          <Box sx={{ width: '100%', height: 250 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: financeData.budgetAllocation.map(item => item.budget),
                  color: '#4CAF50',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: financeData.budgetAllocation.map(item => item.department),
                  id: 'departments',
                },
              ]}
              yAxis={[{ id: 'budget' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="departments"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
              <ChartsYAxis
                axisId="budget"
                tickLabelStyle={{ fontSize: 10, fill: '#94A3B8' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
